class OAuthClient {
  constructor(config) {
    this.clientId = config.clientId;
    this.clientSecret = config.clientSecret;
    this.redirectUri = config.redirectUri;
    this.authorizationEndpoint = config.authorizationEndpoint;
    this.tokenEndpoint = config.tokenEndpoint;
    this.scopes = config.scopes || [];
    this.storageKey = config.storageKey || 'oauth_tokens';
  }

  async authenticate() {
    const tokens = this.getStoredTokens();
    
    if (tokens && this.isTokenValid(tokens.access_token)) {
      return tokens.access_token;
    }
    
    if (tokens && tokens.refresh_token && !this.isTokenValid(tokens.access_token)) {
      try {
        const newTokens = await this.refreshAccessToken(tokens.refresh_token);
        this.storeTokens(newTokens);
        return newTokens.access_token;
      } catch (error) {
        console.error('Token refresh failed:', error);
        this.clearTokens();
        throw error;
      }
    }
    
    this.redirectToLogin();
  }

  redirectToLogin() {
    const params = new URLSearchParams({
      client_id: this.clientId,
      redirect_uri: this.redirectUri,
      response_type: 'code',
      scope: this.scopes.join(' ')
    });
    
    window.location.href = `${this.authorizationEndpoint}?${params}`;
  }

  async handleCallback() {
    const urlParams = new URLSearchParams(window.location.search);
    const code = urlParams.get('code');
    
    if (!code) return null;
    
    try {
      const tokens = await this.exchangeCodeForTokens(code);
      this.storeTokens(tokens);
      window.history.replaceState({}, document.title, window.location.pathname);
      return tokens.access_token;
    } catch (error) {
      console.error('Token exchange failed:', error);
      throw error;
    }
  }

  async exchangeCodeForTokens(code) {
    const response = await fetch(this.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        'Authorization': 'Basic ' + btoa(`${this.clientId}:${this.clientSecret}`)
      },
      body: new URLSearchParams({
        grant_type: 'authorization_code',
        code: code,
        redirect_uri: this.redirectUri
      })
    });

    if (!response.ok) {
      throw new Error(`Token exchange failed: ${response.status}`);
    }

    return await response.json();
  }

  async refreshAccessToken(refreshToken) {
    const response = await fetch(this.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        'Authorization': 'Basic ' + btoa(`${this.clientId}:${this.clientSecret}`)
      },
      body: new URLSearchParams({
        grant_type: 'refresh_token',
        refresh_token: refreshToken
      })
    });

    if (!response.ok) {
      throw new Error(`Token refresh failed: ${response.status}`);
    }

    return await response.json();
  }

  getStoredTokens() {
    const stored = localStorage.getItem(this.storageKey);
    return stored ? JSON.parse(stored) : null;
  }

  storeTokens(tokens) {
    localStorage.setItem(this.storageKey, JSON.stringify(tokens));
  }

  clearTokens() {
    localStorage.removeItem(this.storageKey);
  }

  isTokenValid(accessToken) {
    if (!accessToken) return false;
    
    try {
      const payload = JSON.parse(atob(accessToken.split('.')[1]));
      const currentTime = Math.floor(Date.now() / 1000);
      return payload.exp > currentTime;
    } catch (error) {
      return false;
    }
  }

  async makeAuthenticatedRequest(url, options = {}) {
    const token = await this.authenticate();
    
    return fetch(url, {
      ...options,
      headers: {
        ...options.headers,
        'Authorization': `Bearer ${token}`
      }
    });
  }
}